mapper.select:
select a.id id, a.agent_id agentId, a.parent_id parentId, a.path path, a.agent_account agentAccount, a.level level, a.register_time registerTime from agent_info a join agent_info_relation b on a.agent_id=b.descendant_agent_id
b.ancestor_agent_id in
#{id}

select a.id id, a.agent_id agentId, a.parent_id parentId, a.path path, a.agent_account agentAccount, a.level level, a.register_time registerTime from agent_info a
AND a.parent_id IN
#{value}

select count(1) as count, agent_label_id as agentLabelId
from agent_info
where agent_label_id is not null
and agent_label_id in

    #{item}

group by agent_label_id;

select
a.id,
a.agent_id agentId,
a.agent_account agentAccount,
a.level ,
a.super_remark superRemark,
a.register_time registerTime
from agent_info a
join  agent_info_relation b on a.agent_id=b.descendant_agent_id

    a.site_code = #{vo.siteCode}

        and a.agent_account = #{vo.lowerLevelAccount}



            and b.ancestor_agent_id=#{vo.agentId}
            and a.level  >=  #{vo.level}
            order by a.level asc ,a.created_time asc


            and b.ancestor_agent_id=#{vo.agentId}
            and a.level  >  #{vo.level}
            order by a.created_time desc

select id, agent_id agentId, agent_account agentAccount, level , super_remark superRemark from agent_info where 1=1
AND parent_id in
#{value}

select id, agent_id agentId, agent_account agentAccount, level , super_remark superRemark from agent_info where 1=1
AND agent_account in
#{value}

SELECT merchant_account as merchantAccount, COUNT(*) AS agentCount FROM agent_info WHERE merchant_account IN
#{merchantAccount}
AND level = 1 and site_code = #{siteCode} GROUP BY merchant_account

SELECT * FROM ( WITH RECURSIVE numbers AS ( SELECT 1 AS n UNION ALL SELECT n + 1 FROM numbers WHERE n <= 30 ) SELECT agent_info.id AS id, agent_info.agent_account AS agentAccount, agent_info.bind_short_url_operator AS bindShortUrlOperator, agent_info.bind_short_url_time AS bindShortUrlTime, TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(agent_info.short_url, ',', numbers.n), ',', -1)) AS shortUrl FROM agent_info JOIN numbers ON LENGTH(agent_info.short_url) - LENGTH(REPLACE(agent_info.short_url, ',', '')) >= numbers.n - 1
AND agent_info.site_code = #{param.siteCode}
) t1
AND t1.agentAccount = #{param.agentAccount}
AND t1.shortUrl LIKE CONCAT('%', #{param.shortUrl}, '%')
AND t1.bindShortUrlOperator = #{param.bindShortUrlOperator}
ORDER BY t1.bindShortUrlTime DESC,t1.shortUrl desc

SELECT
 *
FROM agent_info
where 1=1

    and site_code=#{vo.siteCode,jdbcType=VARCHAR}


    and invite_code=#{vo.inviteCode,jdbcType=VARCHAR}


    AND register_time  >=  #{vo.registerTimeStart}


    AND register_time  <=  #{vo.registerTimeEnd}
